import{_ as e,o as s,c as n,O as r}from"./chunks/framework.0d5b6918.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/founder-card.md","filePath":"en/materials/founder-card.md","lastUpdated":1776439080000}'),t={name:"en/materials/founder-card.md"};function i(l,a,c,o,d,p){return s(),n("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell brand-page-shell--founder-card"><section class="brand-hero"><div><p class="brand-kicker">Background Overview</p><h1>Background Overview</h1><div class="brand-hero__panel"><span class="brand-pill">Quick Card</span><strong>ExecFabric is currently being advanced solo from Hangzhou. The long-term mainline is eight years of frontend delivery, with two years of continued reinforcement in Python automation and small full-stack closure. The best first step is still one real workflow or module.</strong><p>It is a better fit to begin with one real business flow first, then expand into governance and reuse.</p></div><p class="brand-lead"> Project fit is still best judged from four angles: <strong>map pages, complex business back offices, data-flow automation, and turning script capabilities into formal entry points</strong> are the most stable delivery combination right now, and the boundary, risk, and delivery mode should be stated clearly before anything expands. </p><div class="brand-chip-list"><span class="brand-chip">8 years frontend delivery</span><span class="brand-chip">2 years closure reinforcement</span><span class="brand-chip">GIS visualization</span><span class="brand-chip">Vue admin frontend</span><span class="brand-chip">Python automation</span><span class="brand-chip">Delivery-oriented engineer</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="/en/contact.html#lead-form">Discuss a real scenario</a><a class="cta-button" href="./resume-public.html">View Projects and Resume</a><a class="cta-button" href="./service-packages.html">View Kickoff Options</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // FOUNDER CARD</span><span>MAT 06</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">main</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">frontend</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">gis</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">plus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">automation</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">delivery</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">real_projects</span></span></div><div class="matrix-panel__callout">SHORT VIEW, REAL DELIVERY SIGNAL</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">role</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">builder</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">style</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">small first</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">usable delivery</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">30s</p><h2>Core delivery scope</h2><p>Map and visualization pages, Vue admin systems, data dashboards, reporting flows, and turning script capabilities into formal entry points are the most stable capability combination right now.</p></article><article class="brand-card"><p class="brand-kicker">Fit</p><h2>Projects that fit best as a first start</h2><p>The best fit is one clear map page, admin module, automation flow, or script-onboarding scenario first, then gradual expansion.</p></article><article class="brand-card"><p class="brand-kicker">Method</p><h2>How the work should move</h2><p>Clarify scope, inputs and outputs, cycle, and exclusions first, then start phase one so the project does not become too wide too early.</p></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Core 01</p><h2>GIS / map visualization</h2><p>Familiar with OpenLayers, Mapbox, and Cesium, with delivery experience across 2D and 3D maps, point linkage, model display, popups, and map-centered business pages.</p></article><article class="brand-card"><p class="brand-kicker">Core 02</p><h2>Vue admin systems / data dashboards</h2><p>Long-term delivery on management systems, large dashboards, and complex business pages, including forms, tables, file upload, real-time logs, and API integration.</p></article><article class="brand-card"><p class="brand-kicker">Core 03</p><h2>Python automation</h2><p>Ongoing work in data collection, cleaning, report generation, export and import, and small to medium backend support, with the ability to close repeated flows into one deliverable unit first.</p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Current Fit</p><h2>Scenarios worth connecting first</h2><ul class="brand-list"><li>GIS visualization, map business pages, and public-sector or enterprise visualization support work.</li><li>Vue admin systems, Ruoyi-style back offices, inherited legacy projects, and frontend joint debugging and maintenance.</li><li>Data dashboards, log displays, and real-time data pages.</li><li>Reports, files, data capture, export flows, and Python automation processes.</li></ul></article><article class="brand-card"><p class="brand-kicker">Boundary</p><h2>Projects that should not be the first entry</h2><ul class="brand-list"><li>Pure backend re-architecture or very large greenfield systems from zero.</li><li>Long-running needs with huge scope but no clear first-phase closure point.</li><li>Very low budgets that still expect long-term onsite work and multi-role full coverage.</li><li>Cases where the real scenario is not defined yet but the scope is already spread too wide.</li></ul></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Public Links</p><h2>Public entry points</h2><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="https://github.com/zmx2321" target="_blank" rel="noreferrer"><span>GitHub</span><strong>zmx2321</strong></a><a class="brand-link-card" href="https://zmx2321.github.io/vite-blog/" target="_blank" rel="noreferrer"><span>Blog</span><strong>vite-blog</strong></a><a class="brand-link-card" href="https://zmx2321.github.io/vue3-admin-demo" target="_blank" rel="noreferrer"><span>Demo</span><strong>vue3-admin-demo</strong></a><a class="brand-link-card" href="mailto:zmx2321@163.com"><span>Email</span><strong>zmx2321@163.com</strong></a></div></article><article class="brand-card"><p class="brand-kicker">More Materials</p><h2>Related pages</h2><ul class="brand-list"><li>View the full delivery background: <a href="./founder-profile.html">Delivery Background and Project History</a></li><li>View the standard resume page: <a href="./resume-public.html">Projects and Resume</a></li><li>View kickoff options: <a href="./service-packages.html">Kickoff Options / Service Packages</a></li></ul></article></section><section class="brand-card brand-card--cta founder-card-next-step"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>Project types worth discussing first</h2><p class="brand-lead">When a map, frontend, or automation chain needs to be filled quickly, the best move is to evaluate one real module, workflow, or script scenario directly and judge the boundary, cycle, and whether it can become a deliverable closed loop.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="/en/contact.html#lead-form"><span>Lead</span><strong>Discuss a real scenario</strong></a><a class="brand-link-card" href="./resume-public.html"><span>Resume</span><strong>Projects and Resume</strong></a><a class="brand-link-card" href="./founder-profile.html"><span>Background</span><strong>Delivery Background and Project History</strong></a><a class="brand-link-card" href="./service-packages.html"><span>Cooperation</span><strong>Kickoff Options</strong></a></div></div></section></div>',1)]))}const b=e(t,[["render",i]]);export{u as __pageData,b as default};
